// HasAccount applies the HasEdge predicate on the "account" edge.
func HasAccount() predicate.NoteConnectionItemMap {
	return predicate.NoteConnectionItemMap(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, AccountTable, AccountColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasAccountWith applies the HasEdge predicate on the "account" edge with a given conditions (other predicates).
func HasAccountWith(preds ...predicate.NoteConnectionAccount) predicate.NoteConnectionItemMap {
	return predicate.NoteConnectionItemMap(func(s *sql.Selector) {
		step := newAccountStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasNote applies the HasEdge predicate on the "note" edge.
func HasNote() predicate.NoteConnectionItemMap {
	return predicate.NoteConnectionItemMap(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, NoteTable, NoteColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasNoteWith applies the HasEdge predicate on the "note" edge with a given conditions (other predicates).
func HasNoteWith(preds ...predicate.Note) predicate.NoteConnectionItemMap {
	return predicate.NoteConnectionItemMap(func(s *sql.Selector) {
		step := newNoteStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.NoteConnectionItemMap) predicate.NoteConnectionItemMap {
	return predicate.NoteConnectionItemMap(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.NoteConnectionItemMap) predicate.NoteConnectionItemMap {
	return predicate.NoteConnectionItemMap(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.NoteConnectionItemMap) predicate.NoteConnectionItemMap {
	return predicate.NoteConnectionItemMap(sql.NotPredicates(p))
}
